  1→import { createHash } from "node:crypto";
  2→import { z } from "zod";
  3→import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
  4→import type { RequestHandlerExtra } from "@modelcontextprotocol/sdk/shared/protocol.js";
  5→import { getCachedSession, setCachedSession } from "./redis.js";
  6→
  7→// Constants
  8→const FASTMAIL_SESSION_ENDPOINT = "https://api.fastmail.com/jmap/session";
  9→
 10→const JMAP_USING = [
 11→  "urn:ietf:params:jmap:core",
 12→  "urn:ietf:params:jmap:mail",
 13→  "urn:ietf:params:jmap:submission",
 14→];
 15→
 16→// --- Method allowlist ---
 17→
 18→export const ALLOWED_METHODS = new Set([
 19→  // Core
 20→  "Core/echo",
 21→  // Mailbox
 22→  "Mailbox/get",
 23→  "Mailbox/query",
 24→  "Mailbox/queryChanges",
 25→  "Mailbox/set",
 26→  // Email
 27→  "Email/get",
 28→  "Email/query",
 29→  "Email/queryChanges",
 30→  "Email/set",
 31→  // Thread
 32→  "Thread/get",
 33→  // SearchSnippet
 34→  "SearchSnippet/get",
 35→  // Identity
 36→  "Identity/get",
 37→  // EmailSubmission
 38→  "EmailSubmission/get",
 39→  "EmailSubmission/query",
 40→  "EmailSubmission/set",
 41→]);
 42→
 43→// --- Types ---
 44→
 45→export interface JMAPSession {
 46→  apiUrl: string;
 47→  uploadUrl: string;
 48→  accountId: string;
 49→}
 50→
 51→type MethodCall = [string, Record<string, unknown>, string];
 52→
 53→export type Safety = "read" | "write" | "destructive";
 54→
 55→// --- Auth helpers ---
 56→
 57→function extractBearerToken(extra: RequestHandlerExtra<any, any>): string {
 58→  const headers = extra.requestInfo?.headers;
 59→
 60→  if (!headers) {
 61→    throw new Error(
 62→      "Missing request headers. Ensure Authorization header is set with 'Bearer <token>' format.",
 63→    );
 64→  }
 65→
 66→  const authHeader = headers["authorization"] || headers["Authorization"];
 67→
 68→  if (!authHeader || typeof authHeader !== "string" || !authHeader.startsWith("Bearer ")) {
 69→    throw new Error(
 70→      "Missing bearer token. Ensure Authorization header is set with 'Bearer <token>' format.",
 71→    );
 72→  }
 73→
 74→  return authHeader.substring(7);
 75→}
 76→
 77→function hashToken(token: string): string {
 78→  return createHash("sha256").update(token).digest("hex").slice(0, 16);
 79→}
 80→
 81→// --- Session management ---
 82→
 83→async function fetchSession(bearerToken: string): Promise<JMAPSession> {
 84→  const response = await fetch(FASTMAIL_SESSION_ENDPOINT, {
 85→    headers: { Authorization: `Bearer ${bearerToken}` },
 86→  });
 87→
 88→  if (!response.ok) {
 89→    throw new Error(`Session fetch failed: HTTP ${response.status}`);
 90→  }
 91→
 92→  const session = (await response.json()) as {
 93→    apiUrl: string;
 94→    uploadUrl: string;
 95→    primaryAccounts: Record<string, string>;
 96→  };
 97→
 98→  const accountId = session.primaryAccounts["urn:ietf:params:jmap:mail"];
 99→  if (!accountId) {
100→    throw new Error("No mail account found in JMAP session");
101→  }
102→
103→  return {
104→    apiUrl: session.apiUrl,
105→    uploadUrl: session.uploadUrl,
106→    accountId,
107→  };
108→}
109→
110→async function getSession(
111→  extra: RequestHandlerExtra<any, any>,
112→): Promise<{ session: JMAPSession; bearerToken: string }> {
113→  const bearerToken = extractBearerToken(extra);
114→  const tokenHash = hashToken(bearerToken);
115→
116→  // Try cached session
117→  const cached = await getCachedSession(tokenHash).catch(() => null);
118→  if (cached) {
119→    const session: JMAPSession = JSON.parse(cached.json);
120→    return { session, bearerToken };
121→  }
122→
123→  // Fetch fresh session
124→  const session = await fetchSession(bearerToken);
125→
126→  // Cache it
127→  await setCachedSession(tokenHash, {
128→    accountId: session.accountId,
129→    json: JSON.stringify(session),
130→  }).catch(() => {}); // Don't fail if Redis is down
131→
132→  return { session, bearerToken };
133→}
134→
135→// --- Validation ---
136→
137→export function validateStructure(methodCalls: unknown): MethodCall[] {
138→  if (!Array.isArray(methodCalls)) {
139→    throw new Error("methodCalls must be an array");
140→  }
141→
142→  if (methodCalls.length === 0) {
143→    throw new Error("methodCalls must not be empty");
144→  }
145→
146→  const callIds = new Set<string>();
147→  const validated: MethodCall[] = [];
148→
149→  for (let i = 0; i < methodCalls.length; i++) {
150→    const call = methodCalls[i];
151→
152→    if (!Array.isArray(call) || call.length !== 3) {
153→      throw new Error(
154→        `methodCalls[${i}]: must be a triple [methodName, args, callId]. Got ${JSON.stringify(call)}`,
155→      );
156→    }
157→
158→    const [method, args, callId] = call;
159→
160→    if (typeof method !== "string") {
161→      throw new Error(`methodCalls[${i}]: method name must be a string`);
162→    }
163→
164→    if (!ALLOWED_METHODS.has(method)) {
165→      throw new Error(
166→        `methodCalls[${i}]: unknown method "${method}". Allowed: ${[...ALLOWED_METHODS].join(", ")}`,
167→      );
168→    }
169→
170→    if (typeof args !== "object" || args === null || Array.isArray(args)) {
171→      throw new Error(`methodCalls[${i}]: args must be an object`);
172→    }
173→
174→    if (typeof callId !== "string") {
175→      throw new Error(`methodCalls[${i}]: callId must be a string`);
176→    }
177→
178→    if (callIds.has(callId)) {
179→      throw new Error(`methodCalls[${i}]: duplicate callId "${callId}"`);
180→    }
181→
182→    callIds.add(callId);
183→    validated.push([method, args as Record<string, unknown>, callId]);
184→  }
185→
186→  return validated;
187→}
188→
189→export function validateResultReferences(methodCalls: MethodCall[]): void {
190→  const seenCallIds = new Set<string>();
191→
192→  for (let i = 0; i < methodCalls.length; i++) {
193→    const [, args, callId] = methodCalls[i];
194→
195→    // Check all args for resultOf references
196→    for (const [key, value] of Object.entries(args)) {
197→      if (
198→        typeof value === "object" &&
199→        value !== null &&
200→        !Array.isArray(value) &&
201→        "resultOf" in value
202→      ) {
203→        const ref = value as Record<string, unknown>;
204→        if (typeof ref.resultOf !== "string") {
205→          throw new Error(`methodCalls[${i}].${key}: resultOf must be a string`);
206→        }
207→        if (!seenCallIds.has(ref.resultOf)) {
208→          throw new Error(
209→            `methodCalls[${i}].${key}: resultOf references "${ref.resultOf}" which has not appeared in an earlier call`,
210→          );
211→        }
212→      }
213→    }
214→
215→    seenCallIds.add(callId);
216→  }
217→}
218→
219→export function validateHygiene(methodCalls: MethodCall[]): void {
220→  for (let i = 0; i < methodCalls.length; i++) {
221→    const [method, args] = methodCalls[i];
222→
223→    // /get calls must include properties (except Mailbox/get and Identity/get which are small)
224→    if (method.endsWith("/get") && method !== "Mailbox/get" && method !== "Identity/get") {
225→      // Allow if ids is a resultOf reference (properties still required)
226→      if (!("properties" in args) || !Array.isArray(args.properties)) {
227→        throw new Error(
228→          `methodCalls[${i}]: ${method} requires a "properties" array. ` +
229→            `Example: ["from", "subject", "receivedAt", "preview"]. ` +
230→            `This prevents fetching unnecessary data.`,
231→        );
232→      }
233→    }
234→
235→    // /query calls must include limit
236→    if (method.endsWith("/query")) {
237→      if (!("limit" in args) || typeof args.limit !== "number") {
238→        throw new Error(
239→          `methodCalls[${i}]: ${method} requires a "limit" (number). Maximum recommended: 50.`,
240→        );
241→      }
242→    }
243→
244→    // Warn about ids: null on /get calls
245→    if (method.endsWith("/get") && "ids" in args && args.ids === null) {
246→      throw new Error(
247→        `methodCalls[${i}]: ${method} with ids: null fetches ALL items. ` +
248→          `Use a /query call first to get specific IDs.`,
249→      );
250→    }
251→  }
252→}
253→
254→export function classifySafety(methodCalls: MethodCall[]): Safety {
255→  let safety: Safety = "read";
256→
257→  for (const [method, args] of methodCalls) {
258→    if (method === "EmailSubmission/set") {
259→      return "destructive"; // Sending email is destructive (can't unsend)
260→    }
261→
262→    if (method.endsWith("/set")) {
263→      const argsObj = args as Record<string, unknown>;
264→
265→      if (argsObj.destroy && Array.isArray(argsObj.destroy) && argsObj.destroy.length > 0) {
266→        return "destructive";
267→      }
268→
269→      if (argsObj.create || argsObj.update) {
270→        safety = "write";
271→      }
272→    }
273→  }
274→
275→  return safety;
276→}
277→
278→// --- Response cleaning ---
279→
280→const STRIP_KEYS = new Set(["state", "queryState", "canCalculateChanges", "position", "accountId"]);
281→
282→export function cleanResponse(methodResponses: unknown[]): unknown[] {
283→  return methodResponses.map((response) => {
284→    if (!Array.isArray(response) || response.length !== 3) {
285→      return response; // Pass through malformed responses
286→    }
287→
288→    const [method, result, callId] = response;
289→
290→    if (typeof result !== "object" || result === null) {
291→      return [method, result, callId];
292→    }
293→
294→    const cleaned: Record<string, unknown> = {};
295→    for (const [key, value] of Object.entries(result as Record<string, unknown>)) {
296→      if (!STRIP_KEYS.has(key)) {
297→        cleaned[key] = value;
298→      }
299→    }
300→
301→    return [method, cleaned, callId];
302→  });
303→}
304→
305→// --- Account ID injection ---
306→
307→export function injectAccountId(methodCalls: MethodCall[], accountId: string): MethodCall[] {
308→  return methodCalls.map(([method, args, callId]) => {
309→    if (!("accountId" in args)) {
310→      return [method, { ...args, accountId }, callId];
311→    }
312→    return [method, args, callId];
313→  });
314→}
315→
316→// --- Execute ---
317→
318→async function execute(
319→  args: { methodCalls: [string, Record<string, unknown>, string][] },
320→  extra: RequestHandlerExtra<any, any>,
321→): Promise<unknown[]> {
322→  // 1. Validate
323→  const validated = validateStructure(args.methodCalls);
324→  validateResultReferences(validated);
325→  validateHygiene(validated);
326→
327→  // 2. Safety check
328→  const safety = classifySafety(validated);
329→  if (safety === "destructive") {
330→    const destructiveOps: string[] = [];
331→    for (const [method, callArgs] of validated) {
332→      if (method === "EmailSubmission/set") {
333→        destructiveOps.push("send email (EmailSubmission/set)");
334→      } else if (method.endsWith("/set")) {
335→        const a = callArgs as Record<string, unknown>;
336→        if (a.destroy && Array.isArray(a.destroy)) {
337→          destructiveOps.push(`destroy ${a.destroy.length} item(s) (${method})`);
338→        }
339→      }
340→    }
341→    throw new Error(
342→      `This request contains destructive operations: ${destructiveOps.join(", ")}. ` +
343→        `Please confirm with the user before retrying with the same request.`,
344→    );
345→  }
346→
347→  // 3. Get session and inject accountId
348→  const { session, bearerToken } = await getSession(extra);
349→  const injectedCalls = injectAccountId(validated, session.accountId);
350→
351→  // 4. Send to Fastmail
352→  const jmapRequest = {
353→    using: JMAP_USING,
354→    methodCalls: injectedCalls,
355→  };
356→
357→  const response = await fetch(session.apiUrl, {
358→    method: "POST",
359→    headers: {
360→      "Content-Type": "application/json",
361→      Authorization: `Bearer ${bearerToken}`,
362→    },
